#include<bits/stdc++.h>
using namespace std;
bool flag=0;
bool ten=1;
int shu=1;
int ans = 0;
int main() {
	string a;
	cin >> a;
	for (int i = 0; i < a.size(); i++) {

		if (a[i] == '+') {
			ten = 1;
			if(flag) shu++;
            flag=1;
		} else if (a[i] == '-') {
			ten = 0;
			if(flag) shu++;
            flag=1;
		} else if (a[i] == '(') {
			int shuu = 0, shuu2 = 0;
			i++;
			while (a[i] >= '0' && a[i] <= '9') {
				shuu += (a[i] - '0');
				shuu *= 10;
				i++;
			}
			shuu /= 10;
			i++;
			while (a[i] >= '0' && a[i] <= '9') {
				shuu2 += (a[i] - '0');
				shuu2 *= 10;
				i++;
			}
			shuu2 /= 10;
			i--;
			ans += (shuu2 * shuu * (int(ten) * 2 - 1));
		} else if (a[i] >= '0' && a[i] <= '9') {
			int shuu2 = 0;
			while (a[i] >= '0' && a[i] <= '9') {
				shuu2 += (a[i] - '0');
				shuu2 *= 10;
				i++;
			}
			shuu2 /= 10;
            i--;
			ans += (shuu2 * shu * (int(ten) * 2 - 1));
            shu=0;

		}
        //cout<<"i:"<<i<<" ans:"<<ans<<"\n";
	}
    cout<<ans;
	return 0;
}
